{"code": "import json
import re

# Read the physical activity papers
with open(locals()['var_functions.query_db:16'], 'r') as f:
    physical_activity_papers = json.load(f)

# Function to extract year from text
def extract_year(text):
    # Look for patterns like YYYY, 'YY, or YYYY in headers
    year_patterns = [
        r'\b(20\d{2})\b',  # 20xx
        r"'\b(\d{2})\b",   # 'xx
    ]

    # Look in the first 1000 characters (usually header)
    header = text[:1000]

    for pattern in year_patterns:
        matches = re.findall(pattern, header)
        for match in matches:
            # Convert 'xx to 20xx
            if len(match) == 2:
                year = int('20' + match)
            else:
                year = int(match)
            # Filter reasonable years for HCI papers (2000-2025)
            if 2000 <= year <= 2025:
                return year
    return None

# Find papers from 2016
papers_from_2016 = []
for paper in physical_activity_papers:
    title = paper['filename'].replace('.txt', '')
    text = paper.get('text', '')
    year = extract_year(text)

    if year == 2016:
        papers_from_2016.append({
            'title': title,
            'id': paper['_id'],
            'year': year
        })

print('__RESULT__:')
print(json.dumps({
    'total_pa_papers': len(physical_activity_papers),
    'papers_2016': papers_from_2016
}))"}

